**Firestore rules (`backend/firestore.rules`):
```
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {
    match /articles/{doc} {
      allow read: if true;
      allow create, update, delete: if request.auth != null &&
        request.resource.data.keys().hasAll(['title', 'content', 'author', 'thumbnailURL', 'publishedAt', 'createdAt']) &&
        request.resource.data.thumbnailURL is string && request.resource.data.thumbnailURL.size() > 0;
    }
  }
}
```
**Storage rules (`backend/storage.rules`):
```
rules_version = '2';
service firebase.storage {
  match /b/{bucket}/o {
    match /media/articles/{allPaths=**} {
      allow read: if true;
      allow write: if request.auth != null &&
        request.resource.size < 10 * 1024 * 1024 &&
        request.resource.contentType.matches('image/.*');
    }
  }
}
```
Deploy: `firebase deploy --only firestore:rules,storage:rules`

