**FirestoreArticleDataSourceImpl**:
```dart
import 'package:cloud_firestore/cloud_firestore.dart';

class FirestoreArticleDataSourceImpl implements FirestoreArticleDataSource {
  final FirebaseFirestore firestore = FirebaseFirestore.instance;

  @override
  Future<void> uploadArticle(ArticleModel article) async {
    await firestore.collection('articles').add(article.toFirestore());
  }

  @override
  Future<List<ArticleModel>> getUserArticles() async {
    final snapshot = await firestore
        .collection('articles')
        .where('isUserArticle', isEqualTo: true)
        .orderBy('createdAt', descending: true)
        .get();
    return snapshot.docs.map((doc) => ArticleModel.fromFirestore(doc)).toList();
  }
}
```
**FirebaseStorageDataSourceImpl**:
```dart
import 'package:firebase_storage/firebase_storage.dart';
import 'package:path/path.dart' as path;
import 'package:uuid/uuid.dart';

class FirebaseStorageDataSourceImpl implements FirebaseStorageDataSource {
  final FirebaseStorage storage = FirebaseStorage.instance;

  @override
  Future<String> uploadThumbnail(String filePath) async {
    final fileName = '${Uuid().v4()}${path.extension(filePath)}';
    final ref = storage.ref().child('media/articles/$fileName');
    final uploadTask = ref.putFile(File(filePath));
    final snapshot = await uploadTask;
    return await snapshot.ref.getDownloadURL();
  }
}
```

