**ArticleRepositoryImpl** extensions:
```dart
class ArticleRepositoryImpl implements ArticleRepository {
  final FirestoreArticleDataSource firestoreDataSource;
  final FirebaseStorageDataSource storageDataSource;

  @override
  Future<DataState<void>> uploadArticle(ArticleEntity article) async {
    try {
      final model = ArticleModel.fromEntity(article);
      await firestoreDataSource.uploadArticle(model);
      return const DataSuccess(null);
    } on FirebaseException catch (e) {
      return DataFailed(e.message ?? 'Upload failed');
    } catch (e) {
      return DataFailed(e.toString());
    }
  }

  @override
  Future<DataState<String>> uploadArticleThumbnail(String filePath) async {
    try {
      final url = await storageDataSource.uploadThumbnail(filePath);
      return DataSuccess(url);
    } catch (e) {
      return DataFailed(e.toString());
    }
  }

  @override
  Future<DataState<List<ArticleEntity>>> getUserArticles() async {
    try {
      final models = await firestoreDataSource.getUserArticles();
      final entities = models.map((m) => m.toEntity()).toList();
      return DataSuccess(entities);
    } catch (e) {
      return DataFailed(e.toString());
    }
  }
}
```

