**States** (`presentation/bloc/article/upload/article_upload_state.dart`):
```dart
abstract class ArticleUploadState extends Equatable {}
class ArticleUploadInitial extends ArticleUploadState {}
class ArticleUploadLoading extends ArticleUploadState {}
class ArticleUploadSuccess extends ArticleUploadState {}
class ArticleUploadFailure extends ArticleUploadState {
  final String message;
  ArticleUploadFailure(this.message);
  @override
  List<Object> get props => [message];
}
```
**Cubit**:
```dart
class ArticleUploadCubit extends Cubit<ArticleUploadState> {
  final UploadArticleUseCase uploadArticle;
  final UploadArticleThumbnailUseCase uploadThumbnail;

  ArticleUploadCubit(this.uploadArticle, this.uploadThumbnail)
      : super(ArticleUploadInitial());

  Future<void> uploadArticle(ArticleEntity article, String? thumbnailFilePath) async {
    emit(ArticleUploadLoading());
    try {
      String? thumbnailUrl;
      if (thumbnailFilePath != null) {
        final thumbResult = await uploadThumbnail(UploadThumbnailParams(thumbnailFilePath));
        thumbnailUrl = thumbResult.data;
      }
      final finalArticle = article.copyWith(
        thumbnailURL: thumbnailUrl,
        isUserArticle: true,
        createdAt: DateTime.now().toIso8601String(),
      );
      await uploadArticle(UploadArticleParams(finalArticle));
      emit(ArticleUploadSuccess());
    } catch (e) {
      emit(ArticleUploadFailure(e.toString()));
    }
  }
}
```

