  create: (_) => getIt<ArticleUploadCubit>(),
  child: BlocConsumer<ArticleUploadCubit, ArticleUploadState>(
    listener: (context, state) {
      if (state is Success) Navigator.pop(context, true);
      if (state is Failure) ScaffoldMessenger.showSnackBar(...);
    },
